import React, { useState, useEffect } from 'react';
import axios from 'axios';

// Настраиваем axios для работы с куками (сессиями)
const api = axios.create({
  baseURL: 'http://localhost:5000', // или ваш URL Flask сервера
  withCredentials: true, // Важно для передачи кук сессии
  headers: {
    'Content-Type': 'application/json',
  },
});

function App() {
  const [formData, setFormData] = useState({
    login: '',
    password: '',
  });
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [protectedData, setProtectedData] = useState('');

  // // Проверяем авторизацию при загрузке приложения
  // useEffect(() => {
  //   checkAuthStatus();
  // }, []);

  // // Функция проверки статуса авторизации
  // const checkAuthStatus = async () => {
  //   try {
  //     // Этот эндпоинт нужно создать на бэкенде
  //     const response = await api.get('/api/current_user');
  //     if (response.data.is_authenticated) {
  //       setIsAuthenticated(true);
  //       setCurrentUser(response.data.user);
  //     }
  //   } catch (error) {
  //     console.log('User is not authenticated');
  //   }
  // };

  // Обработчик изменения полей формы
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value,
    });
  };

  // Обработчик отправки формы
  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    try {
      const response = await api.post('/login', formData);

      if (response.status === 200) {
        setMessage('✅ ' + response.data.message);
        setIsAuthenticated(true);

        // // Получаем информацию о пользователе
        // const userResponse = await api.get('/api/current_user');
        // if (userResponse.data.is_authenticated) {
        //   setCurrentUser(userResponse.data.user);
        // }

        // Очищаем форму
        setFormData({
          login: '',
          password: '',
        });
      }
    } catch (error) {
      if (error.response) {
        // Сервер ответил с ошибкой
        setMessage('❌ ' + (error.response.data.message || 'Login failed'));
      } else {
        setMessage('❌ Network error. Please check your connection.');
      }
    } finally {
      setLoading(false);
    }
  };

  // Выход из системы
  const handleLogout = async () => {
    try {
      const response = await api.post('/logout');
      if (response.status === 200) {
        setIsAuthenticated(false);
        setCurrentUser(null);
        setProtectedData('');
        setMessage('✅ ' + response.data.message);
      }
    } catch (error) {
      setMessage('❌ Logout failed');
    }
  };

  // // Получение защищенных данных
  // const fetchProtectedData = async () => {
  //   try {
  //     const response = await api.get('/api/protected');
  //     setProtectedData(response.data.message || response.data.data);
  //   } catch (error) {
  //     if (error.response && error.response.status === 401) {
  //       setMessage('❌ Session expired. Please login again.');
  //       setIsAuthenticated(false);
  //     } else {
  //       setMessage('❌ Failed to fetch protected data');
  //     }
  //   }
  // };

  // Если пользователь авторизован, показываем другой интерфейс
  if (isAuthenticated) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <h2 style={styles.title}>Welcome, {currentUser?.login || 'User'}!</h2>
          <p style={styles.subtitle}>You are successfully logged in.</p>

          <div style={styles.userInfo}>
            <p><strong>User ID:</strong> {currentUser?.id}</p>
            <p><strong>Login:</strong> {currentUser?.login}</p>
          </div>

          <div style={styles.buttonGroup}>
            <button 
              onClick={fetchProtectedData} 
              style={styles.button}
              disabled={loading}
            >
              Get Protected Data
            </button>

            <button 
              onClick={handleLogout} 
              style={{...styles.button, ...styles.logoutButton}}
              disabled={loading}
            >
              Logout
            </button>
          </div>

          {protectedData && (
            <div style={styles.dataCard}>
              <h3>Protected Data:</h3>
              <p>{protectedData}</p>
            </div>
          )}

          {message && (
            <div style={message.includes('❌') ? styles.error : styles.success}>
              {message}
            </div>
          )}
        </div>
      </div>
    );
  }

  // Форма авторизации
  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Login Form</h2>
        <p style={styles.subtitle}>Enter your credentials to continue</p>

        {message && (
          <div style={message.includes('❌') ? styles.error : styles.success}>
            {message}
          </div>
        )}

        <form onSubmit={handleSubmit} style={styles.form}>
          <div style={styles.formGroup}>
            <label style={styles.label}>
              Login *
            </label>
            <input
              type="text"
              name="login"
              value={formData.login}
              onChange={handleInputChange}
              style={styles.input}
              placeholder="Enter your login"
              required
              disabled={loading}
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>
              Password *
            </label>
            <input
              type="password"
              name="password"
              value={formData.password}
              onChange={handleInputChange}
              style={styles.input}
              placeholder="Enter your password"
              required
              disabled={loading}
            />
          </div>

          <button 
            type="submit" 
            style={styles.submitButton}
            disabled={loading || !formData.login || !formData.password}
          >
            {loading ? (
              <>
                <span style={styles.spinner}></span>
                Loading...
              </>
            ) : (
              'Login'
            )}
          </button>
        </form>

        <div style={styles.hint}>
          <p><strong>Note:</strong> This demo uses Flask-Login with session cookies.</p>
          <p>Check browser DevTools → Application → Cookies to see the session cookie.</p>
        </div>
      </div>
    </div>
  );
}

// Стили компонента
const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    backgroundColor: '#f0f2f5',
    fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
    padding: '20px',
  },
  card: {
    backgroundColor: 'white',
    borderRadius: '12px',
    boxShadow: '0 6px 20px rgba(0, 0, 0, 0.1)',
    padding: '40px',
    width: '100%',
    maxWidth: '450px',
    transition: 'all 0.3s ease',
  },
  title: {
    fontSize: '28px',
    fontWeight: '600',
    color: '#1a1a1a',
    marginBottom: '8px',
    textAlign: 'center',
  },
  subtitle: {
